TriggerOraclev10g.body:
DECLARE
    vro_tkr_usuarios        tkr_usuarios%ROWTYPE;
    vro_tkr_roles_usuario   tkr_roles_usuario%ROWTYPE;
    vro_tkr_hv_usuarios     tkr_hv_usuarios%ROWTYPE;
    vty_clave               tkr_usuarios.clave%TYPE;
BEGIN
    IF pkgca_tkr_usuarios.f_consulta_x_nombres_correo (:new.nombres,
                                                       :new.apellidos,
                                                       :new.correo_electronico,
                                                       vro_tkr_usuarios) = FALSE
    THEN
        vro_tkr_usuarios.id := tkr_usuarios_seq.NEXTVAL;
        vro_tkr_usuarios.nombres := :new.nombres;
        vro_tkr_usuarios.apellidos := :new.apellidos;
        vro_tkr_usuarios.correo_electronico := :new.correo_electronico;
        vro_tkr_usuarios.usuario := :new.usuario;
        vro_tkr_usuarios.id_tipo_identificacion := :new.id_tipo_identificacion;
        vro_tkr_usuarios.identificacion := :new.identificacion;
        vty_clave := DBMS_RANDOM.string ('A', 7);
        vro_tkr_usuarios.clave :=
            DBMS_CRYPTO.hash (UTL_I18N.string_to_raw (LOWER (vty_clave), 'AL32UTF8'), 3);
        vro_tkr_usuarios.id_usuario_creacion := 1;
        vro_tkr_usuarios.fecha_creacion := SYSTIMESTAMP AT TIME ZONE 'America/Bogota';
        vro_tkr_usuarios.telefono := :new.telefono;
        vro_tkr_usuarios.id_estado_usuario := 2;
        vro_tkr_usuarios.estado := 'A';
        vro_tkr_usuarios.id_rol := 4;
        vro_tkr_usuarios.id_perfil_doctor := 1;
        vro_tkr_usuarios.id_pais  := 1;
        pkgtkr_usuarios_dao.p_insertar (vro_tkr_usuarios);

        -- Insertar rol
        vro_tkr_roles_usuario.id := tkr_roles_usuario_seq.NEXTVAL;
        vro_tkr_roles_usuario.id_usuario := vro_tkr_usuarios.id;
        vro_tkr_roles_usuario.id_rol := 4;
        pkgtkr_roles_usuario_dao.p_insertar (vro_tkr_roles_usuario);

        :new.id_usuario := vro_tkr_usuarios.id;
        :new.clave_inicial := vty_clave;
        vro_tkr_hv_usuarios.id := tkr_hv_usuarios_seq.NEXTVAL;
        vro_tkr_hv_usuarios.id_usuario := vro_tkr_usuarios.id;

        BEGIN
            INSERT INTO tkr_hv_usuarios
                 VALUES vro_tkr_hv_usuarios;
        EXCEPTION
            WHEN OTHERS
            THEN
                NULL;
        END;
    --pkgtkr_hv_usuarios_dao.p_insertar(vro_tkr_hv_usuarios);
    END IF;

    IF :new.id IS NULL
    THEN
        :new.id := tkr_solicitud_doctor_seq.NEXTVAL;
    END IF;
END;
